Span<nint> signed = stackalloc nint[] { 1, 2, 3, -4, 5 };
Span<nuint> unsigned = stackalloc nuint[] { 10, 20, 30, 40, 50 };

nint sum = 0;
for (int i = 0; i < signed.Length; i++)
    sum += signed[i];

nuint usum = 0;
for (int i = 0; i < unsigned.Length; i++)
    usum += unsigned[i];

Console.WriteLine($"nint  size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
Console.WriteLine($"Span<nint>  sum: {sum}");
Console.WriteLine($"Span<nuint> sum: {usum}");

